---@type LWnd
local LWnd = LWnd

function LWnd:RegisterRedPointFunc(redPointType,func)
    if not gModelRedPoint then
        return
    end
    if not self._redListenerList then
        self._redListenerList ={}
    end
    local list  = self._redListenerList[redPointType]
    if not list then
        list = {}
        self._redListenerList[redPointType] =list
    end
    table.insert(list,func)
    local isShowRed = gModelRedPoint:CheckShowRedPoint(redPointType)

    func(isShowRed)

    gModelRedPoint:OnRedPointRegister(redPointType)

    if LOG_INFO_ENABLED then
        local str = string.format("[RedPoint]refId %s  wndName %s",redPointType,self:GetWndName())
        print(str)
    end
end

function LWnd:ReleaseRedPointFunc()
    if self._redListenerList then
        for k,v in pairs(self._redListenerList) do
            gModelRedPoint:OnRedPointRelease(k)
        end
    end


    self._redListenerList=nil
    self._redTranList=nil
end

function LWnd:ReleaseRedPointSingleFunc(redPointType,func)
    if not self._redListenerList then
        return
    end
    local list = self._redListenerList[redPointType]
    if not list then
        return
    end
    table.removeidata(list,func)
    if #list == 0 then
        gModelRedPoint:OnRedPointRelease(redPointType)
    end
end

function LWnd:IsNeedRefreshRedPoint()
    return true
end

function LWnd:OnTryRefreshRedPoint(...)

end

function LWnd:_InnerRefreshRedPoint(redPointType)
    if not self._redListenerList or not self:IsNeedRefreshRedPoint() then
        return
    end
    local list  = self._redListenerList[redPointType]
    if not list then
        return
    end
    local showRed = gModelRedPoint:CheckShowRedPoint(redPointType)
    local tempList = {}
    for k,v in ipairs(list) do
        table.insert(tempList,v)
    end

    for k,v in ipairs(tempList) do
        v(showRed)
    end

end

function LWnd:RegisterRedPoint(parentWnd,isClear)
    if not self._redTranList then
        self._redTranList = {}
    end

    if isClear then
        self._redTranList ={}
        self._redListenerList = {}
    end

    if not gModelRedPoint then
        return
    end
    local wndName = self:GetWndName()
    local pathConfig = gModelRedPoint:GetRedPathConfig()
    if not pathConfig then
        return
    end
    local list = pathConfig[wndName]
    if not list then
        return
    end

    local root = self:GetWndTrans()
    if not CS.IsValidObject(root) then
        return
    end
    local wndParent = root.parent

    for k,v in pairs(list) do

        local isIgnore = self._ignoreRedId and self._ignoreRedId[v.typeId]
        if not isIgnore then
            local redPointTran = wndParent:Find(v.path)
            local record = self._redTranList[redPointTran]
            if CS.IsValidObject(redPointTran) then
                if not v.isOnEff then
                    if not record then
                        self._redTranList[redPointTran] = {isEff = v.isOnEff,typeId = v.typeId}
                        local pointType = v.pointType-1
                        self:SetImageActorState(redPointTran,pointType)
                        LxUiHelper.SetImageNativeSize(redPointTran)
                        local redFunc =nil
                        redFunc = function (isShow)
                            if CS.IsValidObject(redPointTran) then
                                CS.ShowObject(redPointTran,isShow)
                            else
                                self:ReleaseRedPointSingleFunc(v.typeId,redFunc)
                            end

                        end
                        self:RegisterRedPointFunc(v.typeId,redFunc)
                    end

                else
                    if not record then
                        self._redTranList[redPointTran] = {isEff = v.isOnEff,typeId = v.typeId}
                    else
                        record.isEff = v.isOnEff
                        record.typeId = v.typeId
                        local effRedTran = record.effRedTran
                        local redFunc =nil
                        redFunc = function (isShow)
                            if CS.IsValidObject(effRedTran) then
                                CS.ShowObject(effRedTran,isShow)
                            else
                                self:ReleaseRedPointSingleFunc(v.typeId,redFunc)
                            end
                        end
                        if record.redFunc then
                            self:ReleaseRedPointSingleFunc(v.typeId,redFunc)
                        end
                        record.redFunc = redFunc
                        self:RegisterRedPointFunc(v.typeId,redFunc)
                    end


                end
            end
        end
    end
end

function LWnd:OnRedPointEffLoaded(tran,redPointTran)
    if not self._redTranList then
        self._redTranList = {}
    end
    local record = self._redTranList[tran]
    if not record then
        record = {}
        self._redTranList[tran] = record
    end
    record.effRedTran = redPointTran
    local redPointType = record.typeId
    if not redPointType then
        return
    end
    if record.redFunc then
        self:ReleaseRedPointSingleFunc(redPointType,record.redFunc)
    end
    local redFunc =nil
    redFunc = function (isShow)
        if CS.IsValidObject(redPointTran) then
            CS.ShowObject(redPointTran,isShow)
        else
            self:ReleaseRedPointSingleFunc(redPointType,redFunc)
        end

    end
    record.redPointTran = redPointTran
    record.redFunc = redFunc
    self:RegisterRedPointFunc(redPointType,redFunc)
end

function LWnd:HideAllRedPoint()
    if not self._redListenerList then
        return
    end
    for k,v in pairs(self._redListenerList) do
        for k1,v1 in ipairs(v) do
            v1(false)
        end
    end
end


function LWnd:RegisterFuncItemRed(funcId,redTran)
    local redId = gModelRedPoint:GetRedIdByFuncId(funcId)
    if not redId then
        return
    end
    if not CS.IsValidObject(redTran) then
        return
    end
    if not self._redTranList then
        self._redTranList = {}
    end

    local record = self._redTranList[redTran]
    if record then
        self:ReleaseRedPointSingleFunc(redId,record.redFunc)
    end

    local redFunc =nil
    redFunc = function (isShow)
        if CS.IsValidObject(redTran) then
            CS.ShowObject(redTran,isShow)
        else
            self:ReleaseRedPointSingleFunc(redId,redFunc)
        end
    end
    record = {
        redFunc = redFunc,
        typeId = redId
    }
    self._redTranList[redTran] = record
    self:RegisterRedPointFunc(redId,redFunc)

end